"""Pipeline de visión para imágenes dermatológicas.Este módulo concentra, en una primera versión, todo el flujo de visión:- preprocesado de la imagen,- segmentación de la lesión,- extracción de características clínicas y de textura.La salida final de este pipeline es un vector de características numéricasque posteriormente se usa para entrenar y evaluar el modelo."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Any, Optionalimport cv2import numpy as npfrom scipy import ndimage as ndifrom skimage import color, exposure, filters, measure, morphology, segmentation, utilfrom skimage.feature import graycomatrix, graycopropsN_FEATURES = 11ZERO_FEATURES = np.zeros(N_FEATURES, dtype=np.float64)class VisionPipeline:    """    Pipeline de procesamiento de imagen para lesiones cutáneas.    Parameters    ----------    structuring_radius : int        Radio del elemento estructurante usado en operaciones morfológicas.    """    def __init__(self, structuring_radius: int = 5) -> None:        self.structuring_element = morphology.disk(structuring_radius)    def preprocess(self, image_rgb: np.ndarray) -> np.ndarray:        """        Aplica preprocesado básico a la imagen RGB.        Pasos:        - ecualización adaptativa del histograma,        - cierre morfológico por canal,        - filtrado mediana por canal.        Parameters        ----------        image_rgb : np.ndarray            Imagen de entrada en formato RGB.        Returns        -------        np.ndarray            Imagen preprocesada.        """        equalized = exposure.equalize_adapthist(image_rgb)        closed = self._apply_per_channel(equalized, morphology.closing, self.structuring_element)        filtered = self._apply_per_channel(closed, filters.median, self.structuring_element)        return filtered    def segment_lesion(        self,        image_rgb: np.ndarray,    ) -> Optional[measure._regionprops.RegionProperties]:        """        Segmenta la lesión y devuelve la región principal detectada.        El procedimiento actual usa:        - conversión a escala de grises,        - detección de bordes con Sobel,        - umbralización tipo Isodata,        - watershed,        - limpieza morfológica,        - selección de la región de mayor área.        Parameters        ----------        image_rgb : np.ndarray            Imagen RGB preprocesada.        Returns        -------        Optional[measure._regionprops.RegionProperties]            Región principal de la lesión, o None si no se detecta ninguna.        """        gray = color.rgb2gray(image_rgb)        elevation = filters.sobel(gray)        threshold = filters.threshold_isodata(gray)        markers = np.zeros_like(gray, dtype=np.int32)        markers[gray > threshold] = 1        markers[gray < threshold] = 2        mask = segmentation.watershed(elevation, markers)        mask = ndi.binary_fill_holes(mask - 1)                mask = morphology.remove_small_objects(mask, max_size=799)        mask = segmentation.clear_border(mask)        labeled = morphology.label(mask)        props = measure.regionprops(labeled)        if not props:            return None        largest_idx = int(np.argmax([region.area for region in props]))        return props[largest_idx]    def extract_features(        self,        image_rgb: np.ndarray,        lesion_region: Optional[measure._regionprops.RegionProperties],    ) -> np.ndarray:        """        Extrae un vector de características a partir de la lesión segmentada.        Características actuales:        - asimetría,        - excentricidad,        - compactitud,        - 3 descriptores de color,        - diámetro equivalente,        - 4 descriptores de textura GLCM.        Parameters        ----------        image_rgb : np.ndarray            Imagen RGB preprocesada.        lesion_region : Optional[measure._regionprops.RegionProperties]            Región segmentada principal.        Returns        -------        np.ndarray            Vector de características de tamaño fijo.            Si no hay región válida, devuelve un vector de ceros.        """        if lesion_region is None or lesion_region.area <= 0:            return ZERO_FEATURES.copy()        area = float(lesion_region.area)        gray = color.rgb2gray(image_rgb)        # Asimetría aproximada mediante comparación con espejos horizontal y vertical.        mask = lesion_region.image        h_diff = np.count_nonzero(mask & ~np.fliplr(mask))        v_diff = np.count_nonzero(mask & ~np.flipud(mask))        asymmetry = float(0.5 * ((h_diff / area) + (v_diff / area)))        # Compactitud del contorno.        compactness = float((lesion_region.perimeter ** 2) / (4 * np.pi * area + 1e-8))        # Estadísticos simples de color en la región de interés.        row_slice, col_slice = lesion_region.slice        roi = image_rgb[row_slice, col_slice]        color_stats = []        for channel_idx in range(3):            channel = roi[:, :, channel_idx]            channel_max = float(np.max(channel)) + 1e-6            color_stats.append(float(np.std(channel) / channel_max))        # Diámetro equivalente de la región segmentada.        eq_diam = float(lesion_region.equivalent_diameter_area)        # Descriptores de textura GLCM.        glcm = graycomatrix(            util.img_as_ubyte(gray),            distances=[1],            angles=[0, np.pi / 4, np.pi / 2],            symmetric=True,            normed=True,        )        texture = [            float(np.mean(graycoprops(glcm, prop)))            for prop in ("correlation", "homogeneity", "energy", "contrast")        ]        return np.array(            [                asymmetry,                float(lesion_region.eccentricity),                compactness,                *color_stats,                eq_diam,                *texture,            ],            dtype=np.float64,        )    def process_image_path(self, image_path: Path) -> np.ndarray:        """        Procesa una imagen desde disco y devuelve su vector de características.        Parameters        ----------        image_path : Path            Ruta de la imagen.        Returns        -------        np.ndarray            Vector de características.            Si la imagen no puede leerse, devuelve un vector de ceros.        """        img_bgr = cv2.imread(str(image_path))        if img_bgr is None:            return ZERO_FEATURES.copy()        img_rgb = cv2.cvtColor(img_bgr, cv2.COLOR_BGR2RGB)        preprocessed = self.preprocess(img_rgb)        lesion_region = self.segment_lesion(preprocessed)        return self.extract_features(preprocessed, lesion_region)    @staticmethod    def _apply_per_channel(image: np.ndarray, func: Any, kernel: np.ndarray) -> np.ndarray:        """        Aplica una función a cada canal de la imagen por separado.        Parameters        ----------        image : np.ndarray            Imagen multicanal.        func : Any            Función a aplicar a cada canal.        kernel : np.ndarray            Kernel o elemento estructurante usado por la función.        Returns        -------        np.ndarray            Imagen resultante tras procesar cada canal.        """        channels = [func(image[:, :, c], kernel) for c in range(image.shape[2])]        return np.stack(channels, axis=-1)